// Pull every quantified ensures-conjunct into the proof context once for each
// post-state. This way, the foralls for post1_self_ and post2_self_ have
// matching trigger shapes available simultaneously instead of being buried
// inside the ensures conjunct of det_share_mapping where z3 only instantiates
// them under their own #![trigger] pattern.

assert(forall|p_ptr: ProcPtr| #![auto]
    post1_self_.proc_dom().contains(p_ptr) ==>
        post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
assert(forall|p_ptr: ProcPtr| #![auto]
    post2_self_.proc_dom().contains(p_ptr) ==>
        post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));

assert(forall|p_ptr: ProcPtr| #![auto]
    post1_self_.proc_dom().contains(p_ptr) && p_ptr != target_proc_ptr ==>
        post1_self_.get_address_space(p_ptr) =~= pre_self_.get_address_space(p_ptr));
assert(forall|p_ptr: ProcPtr| #![auto]
    post2_self_.proc_dom().contains(p_ptr) && p_ptr != target_proc_ptr ==>
        post2_self_.get_address_space(p_ptr) =~= pre_self_.get_address_space(p_ptr));

assert(forall|t_ptr: ThreadPtr| #![auto]
    post1_self_.thread_dom().contains(t_ptr) ==>
        post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
assert(forall|t_ptr: ThreadPtr| #![auto]
    post2_self_.thread_dom().contains(t_ptr) ==>
        post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));

assert(forall|c_ptr: ContainerPtr| #![auto]
    post1_self_.container_dom().contains(c_ptr) ==>
        post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr)
        && post1_self_.get_container_owned_pages(c_ptr) =~= pre_self_.get_container_owned_pages(c_ptr));
assert(forall|c_ptr: ContainerPtr| #![auto]
    post2_self_.container_dom().contains(c_ptr) ==>
        post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr)
        && post2_self_.get_container_owned_pages(c_ptr) =~= pre_self_.get_container_owned_pages(c_ptr));

assert(forall|e_ptr: EndpointPtr| #![auto]
    post1_self_.endpoint_dom().contains(e_ptr) ==>
        post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
assert(forall|e_ptr: EndpointPtr| #![auto]
    post2_self_.endpoint_dom().contains(e_ptr) ==>
        post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));

assert(forall|p: Pcid|
    #![trigger post1_self_.mem_man.pcid_active(p)]
    #![trigger post1_self_.mem_man.pcid_to_proc_ptr(p)]
    post1_self_.mem_man.pcid_active(p) ==>
        pre_self_.mem_man.pcid_to_proc_ptr(p) == post1_self_.mem_man.pcid_to_proc_ptr(p));
assert(forall|p: Pcid|
    #![trigger post2_self_.mem_man.pcid_active(p)]
    #![trigger post2_self_.mem_man.pcid_to_proc_ptr(p)]
    post2_self_.mem_man.pcid_active(p) ==>
        pre_self_.mem_man.pcid_to_proc_ptr(p) == post2_self_.mem_man.pcid_to_proc_ptr(p));

assert(forall|p: PagePtr|
    #![trigger post1_self_.page_alloc.page_is_mapped(p)]
    post1_self_.page_alloc.page_is_mapped(p) == pre_self_.page_alloc.page_is_mapped(p));
assert(forall|p: PagePtr|
    #![trigger post2_self_.page_alloc.page_is_mapped(p)]
    post2_self_.page_alloc.page_is_mapped(p) == pre_self_.page_alloc.page_is_mapped(p));

assert(forall|p: PagePtr|
    #![trigger post1_self_.page_alloc.page_is_mapped(p)]
    post1_self_.page_alloc.page_is_mapped(p) && p != entry.addr ==>
        pre_self_.get_physical_page_reference_counter(p)
        == post1_self_.get_physical_page_reference_counter(p));
assert(forall|p: PagePtr|
    #![trigger post2_self_.page_alloc.page_is_mapped(p)]
    post2_self_.page_alloc.page_is_mapped(p) && p != entry.addr ==>
        pre_self_.get_physical_page_reference_counter(p)
        == post2_self_.get_physical_page_reference_counter(p));

assert(forall|page_ptr: PagePtr|
    #![trigger post1_self_.page_mapping@[page_ptr]]
    pre_self_.page_mapping@.dom().contains(page_ptr) && page_ptr != entry.addr ==>
        pre_self_.page_mapping@[page_ptr] == post1_self_.page_mapping@[page_ptr]);
assert(forall|page_ptr: PagePtr|
    #![trigger post2_self_.page_mapping@[page_ptr]]
    pre_self_.page_mapping@.dom().contains(page_ptr) && page_ptr != entry.addr ==>
        pre_self_.page_mapping@[page_ptr] == post2_self_.page_mapping@[page_ptr]);

// Domain-level equalities: both post-states share the pre-state's domains.
assert(post1_self_.proc_dom() == post2_self_.proc_dom());
assert(post1_self_.thread_dom() == post2_self_.thread_dom());
assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());
assert(post1_self_.container_dom() == post2_self_.container_dom());
assert(post1_self_.get_num_of_free_pages() == post2_self_.get_num_of_free_pages());
assert(post1_self_.page_mapping@.dom() == post2_self_.page_mapping@.dom());

// Derive cross-run pointwise equalities. Each `assert forall ... by` forces
// z3 to instantiate the post1_self_ and post2_self_ ensures at the SAME witness
// because the goal mentions both trigger shapes.

assert forall|p_ptr: ProcPtr| #![auto]
    post1_self_.proc_dom().contains(p_ptr)
    implies post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr)
by {
    assert(post2_self_.proc_dom().contains(p_ptr));
}

assert forall|p_ptr: ProcPtr| #![auto]
    post1_self_.proc_dom().contains(p_ptr) && p_ptr != target_proc_ptr
    implies post1_self_.get_address_space(p_ptr) =~= post2_self_.get_address_space(p_ptr)
by {
    assert(post2_self_.proc_dom().contains(p_ptr));
}

assert(post1_self_.get_address_space(target_proc_ptr)
        =~= post2_self_.get_address_space(target_proc_ptr));

assert forall|t_ptr: ThreadPtr| #![auto]
    post1_self_.thread_dom().contains(t_ptr)
    implies post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr)
by {
    assert(post2_self_.thread_dom().contains(t_ptr));
}

assert forall|c_ptr: ContainerPtr| #![auto]
    post1_self_.container_dom().contains(c_ptr)
    implies post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr)
        && post1_self_.get_container_owned_pages(c_ptr)
            =~= post2_self_.get_container_owned_pages(c_ptr)
by {
    assert(post2_self_.container_dom().contains(c_ptr));
}

assert forall|e_ptr: EndpointPtr| #![auto]
    post1_self_.endpoint_dom().contains(e_ptr)
    implies post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr)
by {
    assert(post2_self_.endpoint_dom().contains(e_ptr));
}

assert forall|p: Pcid|
    #![trigger post1_self_.mem_man.pcid_to_proc_ptr(p), post2_self_.mem_man.pcid_to_proc_ptr(p)]
    post1_self_.mem_man.pcid_active(p) && post2_self_.mem_man.pcid_active(p)
    implies post1_self_.mem_man.pcid_to_proc_ptr(p) == post2_self_.mem_man.pcid_to_proc_ptr(p)
by { }

assert forall|p: PagePtr|
    #![trigger post1_self_.page_alloc.page_is_mapped(p), post2_self_.page_alloc.page_is_mapped(p)]
    true
    implies post1_self_.page_alloc.page_is_mapped(p)
        == post2_self_.page_alloc.page_is_mapped(p)
by { }

assert forall|p: PagePtr|
    #![trigger post1_self_.page_alloc.page_is_mapped(p), post2_self_.page_alloc.page_is_mapped(p)]
    p != entry.addr && pre_self_.page_alloc.page_is_mapped(p)
    implies post1_self_.get_physical_page_reference_counter(p)
        == post2_self_.get_physical_page_reference_counter(p)
by {
    assert(post1_self_.page_alloc.page_is_mapped(p));
    assert(post2_self_.page_alloc.page_is_mapped(p));
}

assert(post1_self_.get_physical_page_reference_counter(entry.addr)
        == post2_self_.get_physical_page_reference_counter(entry.addr));

assert forall|page_ptr: PagePtr|
    #![trigger post1_self_.page_mapping@[page_ptr], post2_self_.page_mapping@[page_ptr]]
    pre_self_.page_mapping@.dom().contains(page_ptr) && page_ptr != entry.addr
    implies post1_self_.page_mapping@[page_ptr] == post2_self_.page_mapping@[page_ptr]
by { }

assert(post1_self_.page_mapping@[entry.addr] == post2_self_.page_mapping@[entry.addr]);

// Container-of-target-proc field equalities — both post-states preserve every
// listed sub-field of pre_self_'s owning container, so they agree pointwise.
assert(post1_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).owned_procs
        =~= post2_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).owned_procs);
assert(post1_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).parent
        =~= post2_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).parent);
assert(post1_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).parent_rev_ptr
        =~= post2_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).parent_rev_ptr);
assert(post1_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).children
        =~= post2_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).children);
assert(post1_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).owned_endpoints
        =~= post2_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).owned_endpoints);
assert(post1_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).owned_threads
        =~= post2_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).owned_threads);
assert(post1_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).quota
        =~= post2_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).quota);
assert(post1_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).owned_cpus
        =~= post2_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).owned_cpus);
assert(post1_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).scheduler
        =~= post2_self_.get_container(pre_self_.get_proc(target_proc_ptr).owning_container).scheduler);
